const failures = [];
const requireFile = (path) => {
  if (!fs.existsSync(path)) {
    failures.push(`missing required artifact: ${path}`);
    return {};
  }

  return JSON.parse(fs.readFileSync(path, "utf8"));
};

const readOptional = (path) => fs.existsSync(path)
  ? JSON.parse(fs.readFileSync(path, "utf8"))
  : null;

const countNulls = (value) => {
  if (value === null) {
    return 1;
  }

  if (Array.isArray(value)) {
    return value.reduce((sum, item) => sum + countNulls(item), 0);
  }

  if (typeof value === "object" && value !== null) {
    return Object.values(value).reduce((sum, item) => sum + countNulls(item), 0);
  }

  return 0;
};

const assert = (condition, message) => {
  if (!condition) {
    failures.push(message);
  }
};

const includesAll = (actual, expected) => {
  const actualSet = new Set(actual ?? []);
  return expected.every((item) => actualSet.has(item));
};

