for (const [label, validation, templatePath] of [
  ["W/Z", phase201.wzValidation, phase201.wzTemplatePath],
  ["Higgs", phase201.higgsValidation, phase201.higgsTemplatePath],
]) {
  const template = templatePath ? readOptional(templatePath) : null;
  if (!template) {
    failures.push(`Phase201 ${label} template path is missing or unreadable: ${templatePath ?? "<unset>"}`);
    continue;
  }

  const nullCount = countNulls(template);
  if (nullCount > 0 || template.status === "template-unfilled") {
    assert(validation?.promotable === false, `Phase201 ${label} null placeholders or unfilled template status cannot be treated as promotable evidence.`);
  }

  if (validation?.promotable === true) {
    assert(nullCount === 0, `Phase201 ${label} promotable validation cannot contain null placeholders.`);
    assert(template.status !== "template-unfilled", `Phase201 ${label} promotable validation cannot use template-unfilled status.`);
  }
}

if (failures.length > 0) {
  console.error("boson-claim-integrity-failed");
  for (const failure of failures) {
    console.error(`- ${failure}`);
  }
  process.exit(1);
}

